44	namespace {
45	/// Result of validation - contains optional value and error message
46	template <typename T>
47	struct ValidationResult {
48	  std::optional<T> value;
49	  std::string errorMessage;
50	
51	  bool isValid() const { return value.has_value(); }
52	  explicit operator bool() const { return isValid(); }
53	};
