56	static InFlightDiagnostic
57	emitDiagnostic(Location loc, StringRef msg = StringRef(),
58	               DiagnosticSeverity severity = DiagnosticSeverity::Warning) {
59	  return severity == DiagnosticSeverity::Error ? emitError(loc, msg)
60	                                               : emitWarning(loc, msg);
61	}
