63	/// Validate num_cta_in_cga parameter and return the value if valid.
64	/// Returns nullopt with error message if invalid (when key is provided).
65	/// Pass empty key from getters to skip error message construction.
66	static ValidationResult<uint64_t> validateNumCTAInCGA(Attribute attr,
67	                                                      StringRef context) {
68	  auto intAttr = dyn_cast_or_null<IntegerAttr>(attr);
69	  if (!intAttr) {
70	    return {std::nullopt, ("integer value expected for " + context + "." +
71	                           OptimizationHintsAttr::kNumCTAInCGA)
72	                              .str()};
73	  }
74	  // Ampere/ada don't support multiple CTAs in a CGA.
75	  static const SmallVector<StringLiteral, 5> restrictedArchs = {
76	      "sm_80", "sm_86", "sm_87", "sm_88", "sm_89"};
77	  bool requiresSingleCTA = any_of(restrictedArchs, [&](StringRef arch) {
78	    return context.starts_with(arch);
79	  });
80	  uint64_t numCTA = intAttr.getInt();
81	  if (requiresSingleCTA && numCTA != 1) {
82	    return {std::nullopt, ("expected 1 for " + context + "." +
83	                           OptimizationHintsAttr::kNumCTAInCGA)
84	                              .str()};
85	  }
86	  // Must be power of 2, non-zero, and <= 16
87	  if ((numCTA == 0) || (numCTA > 16) || ((numCTA & (numCTA - 1)) != 0)) {
88	    return {std::nullopt, ("expected power-of-two ≤ 16 for " + context + "." +
89	                           OptimizationHintsAttr::kNumCTAInCGA)
90	                              .str()};
91	  }
92	  return {numCTA, ""};
93	}
