95	static ValidationResult<uint64_t>
96	validateNumWorkerWarpsPerCTA(Attribute attr, StringRef context) {
97	  auto intAttr = dyn_cast_or_null<IntegerAttr>(attr);
98	  if (!intAttr) {
99	    return {std::nullopt, ("integer value expected for " + context + "." +
100	                           OptimizationHintsAttr::kNumWorkerWarpsPerCTA)
101	                              .str()};
102	  }
103	  int numWarps = intAttr.getInt();
104	  // Must be power of 2, non-zero, and <= 32
105	  if ((numWarps == 0) || (numWarps > 32) || ((numWarps & (numWarps - 1)) != 0)) {
106	    return {std::nullopt, ("expected power-of-two ≤ 32 for " + context + "." +
107	                           OptimizationHintsAttr::kNumWorkerWarpsPerCTA)
108	                              .str()};
109	  }
110	  // TODO: Currently only support 4 or 8 warps for no functionality check.
111	  if (numWarps != 4 && numWarps != 8) {
112	    numWarps = std::clamp(numWarps, 4, 8);
113	  }
114	  return {numWarps, ""};
115	}
