179	/// Helper function to retrieve an attribute from SM-specific or default entry.
180	/// Returns the attribute if found, otherwise std::nullopt.
181	std::optional<Attribute>
182	OptimizationHintsAttr::getAttributeForSmOrDefault(DictionaryAttr value,
183	                                                  StringRef sm, StringRef key) {
184	  if (value.empty())
185	    return std::nullopt;
186	
187	  // Try SM-specific entry first
188	  if (auto smEntry = value.getAs<DictionaryAttr>(sm))
189	    if (Attribute attr = smEntry.get(key))
190	      return attr;
191	
192	  // Fall back to default entry
193	  if (auto defaultEntry = value.getAs<DictionaryAttr>(kDefault))
194	    if (Attribute attr = defaultEntry.get(key))
195	      return attr;
196	
197	  return std::nullopt;
198	}
