200	// Return failure() if hints are not supported for current operations/target
201	LogicalResult OptimizationHintsAttr::verifyParamWithContext(
202	    Location loc, StringRef context, ArrayRef<StringRef> keysValidForOperation,
203	    DictionaryAttr &attr) {
204	  // Fast return if not warning about hints
205	  if (!cast<CudaTileDialect>(getDialect()).getWarnUnsupportedHints())
206	    return success();
207	
208	  // Handle unallowed architecture key
209	  if (!isKnownKey(context))
210	    return emitDiagnostic(loc) << "unknown hint key " << context;
211	
212	  LogicalResult res = success();
213	  for (auto param : attr) {
214	    StringRef key = param.getName().strref();
215	
216	    if (!keysValidForOperation.empty() &&
217	        !is_contained(keysValidForOperation, key)) {
218	      res = emitDiagnostic(loc)
219	            << key << " is not known hint for current Operation";
220	      continue;
221	    }
222	
223	    if (key == kNumCTAInCGA) {
224	      auto result = validateNumCTAInCGA(param.getValue(), context);
225	      if (!result.isValid())
226	        res = emitDiagnostic(loc) << result.errorMessage;
227	    } else if (key == kNumWorkerWarpsPerCTA) {
228	      auto result = validateNumWorkerWarpsPerCTA(param.getValue(), context);
229	      if (!result.isValid())
230	        res = emitDiagnostic(loc) << result.errorMessage;
231	    } else if (key == kAllowTMA) {
232	      auto result = validateAllowTMA(param.getValue(), context);
233	      if (!result.isValid())
234	        res = emitDiagnostic(loc) << result.errorMessage;
235	    } else if (key == kLatency) {
236	      auto result = validateLatency(param.getValue(), context);
237	      if (!result.isValid())
238	        res = emitDiagnostic(loc) << result.errorMessage;
239	    } else if (key == kOccupancy) {
240	      auto result = validateOccupancy(param.getValue(), context);
241	      if (!result.isValid())
242	        res = emitDiagnostic(loc) << result.errorMessage;
243	    } else {
244	      // Unknown parameter
245	      res = emitDiagnostic(loc)
246	            << "unknown param " << key << " for " << context;
247	    }
248	  }
249	
250	  // Return failure if warnings were printed
251	  // Error (if errorOnHints not set) would be suppressed outside
252	  return res;
253	}
