255	LogicalResult
256	OptimizationHintsAttr::verify(function_ref<InFlightDiagnostic()> emitError,
257	                              DictionaryAttr value) {
258	  for (NamedAttribute entry : value.getValue()) {
259	    if (!isa<DictionaryAttr>(entry.getValue()))
260	      return emitError()
261	             << "expected dictionary attribute for optimization_hints entry `"
262	             << entry.getName().strref() << "` got value=" << entry.getValue();
263	  }
264	  return success();
265	}
