267	LogicalResult OptimizationHintsAttr::verifyWithOp(Operation *op,
268	                                                  DictionaryAttr value) {
269	  Location loc = op->getLoc();
270	  bool errorOnHints = cast<CudaTileDialect>(getDialect()).getErrorOnHints();
271	  SmallVector<StringRef, 4> keysValidForOperation;
272	  if (op != nullptr) {
273	    // Initialize list of supported hints for EntryOp
274	    if (isa<EntryOp>(op)) {
275	      keysValidForOperation.push_back(kNumCTAInCGA);
276	      keysValidForOperation.push_back(kNumWorkerWarpsPerCTA);
277	      keysValidForOperation.push_back(kOccupancy);
278	    }
279	    // Initialize list of supported hints for Load/Store Ops
280	    if (isa<LoadViewTkoOp, StoreViewTkoOp, LoadPtrTkoOp, StorePtrTkoOp>(op)) {
281	      keysValidForOperation.push_back(kLatency);
282	      if (isa<LoadViewTkoOp, StoreViewTkoOp>(op))
283	        keysValidForOperation.push_back(kAllowTMA);
284	    }
285	  }
286	
287	  for (NamedAttribute entry : value.getValue()) {
288	    StringRef key = entry.getName().strref();
289	
290	    auto innerDict = dyn_cast<DictionaryAttr>(entry.getValue());
291	    if (!innerDict)
292	      return op->emitOpError()
293	             << "expected dictionary attribute for optimization_hints entry `"
294	             << key << "` got value=" << entry.getValue();
295	
296	    if (failed(
297	            verifyParamWithContext(loc, key, keysValidForOperation, innerDict)))
298	      if (errorOnHints)
299	        return failure();
300	  }
301	
302	  return success();
303	}
