369	Attribute OptimizationHintsAttr::parse(AsmParser &parser, Type odsType) {
370	  if (parser.parseLess())
371	    return {};
372	  if (succeeded(parser.parseOptionalGreater()))
373	    return OptimizationHintsAttr::get(parser.getContext(),
374	                                      DictionaryAttr::get(parser.getContext()));
375	
376	  NamedAttrList entries;
377	
378	  auto parseOneEntry = [&]() -> ParseResult {
379	    std::string key;
380	    Attribute rawAttr;
381	    DictionaryAttr dataDict;
382	    if (parser.parseKeywordOrString(&key) || parser.parseEqual() ||
383	        parser.parseAttribute(rawAttr))
384	      return failure();
385	
386	    if (entries.get(key))
387	      return parser.emitError(parser.getCurrentLocation())
388	             << "duplicate optimization_hints key `" << key << "`";
389	
390	    dataDict = dyn_cast<DictionaryAttr>(rawAttr);
391	    if (!dataDict)
392	      return parser.emitError(parser.getCurrentLocation())
393	             << "expected dictionary attribute for optimization_hints entry `"
394	             << key << "` got value=" << rawAttr;
395	
396	    entries.append(key, dataDict);
397	    return success();
398	  };
399	  if (parser.parseCommaSeparatedList(AsmParser::Delimiter::None, parseOneEntry))
400	    return {};
401	  if (parser.parseGreater())
402	    return {};
403	
404	  return OptimizationHintsAttr::get(
405	      parser.getContext(), parser.getBuilder().getDictionaryAttr(entries));
406	}
