408	void OptimizationHintsAttr::print(AsmPrinter &printer) const {
409	  printer << "<";
410	  llvm::interleaveComma(getValue(), printer, [&](NamedAttribute attr) {
411	    printer << attr.getName().strref() << " = {";
412	    llvm::interleaveComma(mlir::cast<DictionaryAttr>(attr.getValue()), printer,
413	                          [&](NamedAttribute na) {
414	                            printer << na.getName().strref() << " = ";
415	                            printer.printAttributeWithoutType(na.getValue());
416	                          });
417	    printer << "}";
418	  });
419	  printer << ">";
420	}
