422	LogicalResult DivByAttr::verifyWithAssumeOp(Operation *op) const {
423	  auto assumeOp = llvm::cast<AssumeOp>(op);
424	
425	  // Make sure divisor is a positive power of 2.
426	  uint64_t divisor = getDivisor();
427	  bool isPowerOfTwo = divisor > 0 && ((divisor & (divisor - 1)) == 0);
428	  if (!isPowerOfTwo)
429	    return op->emitOpError() << "'" << name << "' divisor must be a power of 2";
430	
431	  if (!llvm::all_equal({getEvery().has_value(), getAlong().has_value()}))
432	    return op->emitOpError()
433	           << "'" << name << "' 'every'/'along' must be used in combination";
434	
435	  // Verify that the divisor is not larger than 4611686018427387904. This is a
436	  // technical limitation of the current implementation that could be lifted.
437	  if (divisor > 4611686018427387904)
438	    return op->emitOpError() << "'" << name << "' divisor is too large";
439	
440	  // TensorViewType
441	  if (auto tensorViewType =
442	          llvm::dyn_cast<cuda_tile::TensorViewType>(assumeOp.getType())) {
443	    if (getEvery().has_value())
444	      return op->emitOpError() << "'" << name
445	                               << "' 'every'/'along' cannot be used if the "
446	                                  "constrained value is a tensor_view";
447	    return success();
448	  }
449	
450	  // TileType
451	  auto tileType = llvm::dyn_cast<cuda_tile::TileType>(assumeOp.getType());
452	  if (!tileType)
453	    return op->emitOpError() << "'" << name
454	                             << "' is valid only for tile of integer/pointer "
455	                                "or tensor_view values";
456	  if (tileType.getRank() == 0 && getEvery().has_value())
457	    return op->emitOpError() << "'" << name
458	                             << "' 'every'/'along' cannot be used if the "
459	                                "constrained value is a 0D tile";
460	  Type elType = tileType.getElementType();
461	  if (!llvm::isa<cuda_tile::PointerType, IntegerType>(elType))
462	    return op->emitOpError() << "'" << name
463	                             << "' is valid only for tile of integer/pointer "
464	                                "or tensor_view values";
465	
466	  // Verify every/along.
467	  if (!getEvery().has_value())
468	    return success();
469	  if (*getAlong() < 0 || *getAlong() >= tileType.getRank())
470	    return op->emitOpError()
471	           << "'" << name << "' every_dim (" << *getAlong()
472	           << ") must be >= 0 and < tile rank (" << tileType.getRank() << ")";
473	  if (*getEvery() < 0 || *getEvery() > tileType.getDimSize(*getAlong()))
474	    return op->emitOpError() << "expected '" << name
475	                             << "' every_dim to be within 0 and the size of "
476	                                "the respective dimension ("
477	                             << tileType.getDimSize(*getAlong()) << ")";
478	  return success();
479	}
