481	Attribute DivByAttr::parse(AsmParser &parser, Type odsType) {
482	  // Parse literal '<'.
483	  if (parser.parseLess())
484	    return {};
485	
486	  // Parse variable 'divisor'.
487	  uint64_t divisor = 0;
488	  if (parser.parseInteger(divisor)) {
489	    parser.emitError(parser.getCurrentLocation(),
490	                     "failed to parse parameter 'divisor' which is expected to "
491	                     "be an integer");
492	    return {};
493	  }
494	
495	  // Parse 'every' and 'along'.
496	  std::optional<int64_t> every = std::nullopt;
497	  std::optional<int64_t> along = std::nullopt;
498	  if (succeeded(parser.parseOptionalComma())) {
499	    // Parse optional every/along.
500	    int64_t everyVal = -1, alongVal = -1;
501	    if (parser.parseKeyword("every") || parser.parseInteger(everyVal) ||
502	        parser.parseKeyword("along") || parser.parseInteger(alongVal))
503	      return {};
504	    every = everyVal;
505	    along = alongVal;
506	  }
507	
508	  // Parse literal '>'.
509	  if (parser.parseGreater())
510	    return {};
511	
512	  return DivByAttr::get(parser.getContext(), divisor, every, along);
513	}
514	
515	void DivByAttr::print(AsmPrinter &printer) const {
516	  printer << "<" << getDivisor();
517	  if (getEvery().has_value())
518	    printer << ", every " << *getEvery() << " along " << *getAlong();
519	  printer << ">";
520	}
