522	LogicalResult SameElementsAttr::verifyWithAssumeOp(Operation *op) const {
523	  auto assumeOp = llvm::cast<AssumeOp>(op);
524	  auto tileType = llvm::dyn_cast<cuda_tile::TileType>(assumeOp.getType());
525	  if (!tileType)
526	    return op->emitOpError()
527	           << "'" << name
528	           << "' is valid only for tile of integer/pointer values";
529	  if (!llvm::isa<cuda_tile::PointerType, IntegerType>(
530	          tileType.getElementType()))
531	    return op->emitOpError()
532	           << "'" << name
533	           << "' is valid only for tile of integer/pointer values";
534	  if (getValues().size() != tileType.getRank())
535	    return op->emitOpError()
536	           << "expected number of values in '" << name << "' ("
537	           << getValues().size() << ") to match rank of constrained tile ("
538	           << tileType.getRank() << ")";
539	  for (int64_t i = 0, e = tileType.getRank(); i < e; ++i) {
540	    if (getValues()[i] < 0 || getValues()[i] > tileType.getDimSize(i))
541	      return op->emitOpError()
542	             << "expected '" << name << "' value " << i
543	             << " to be within 0 and the size of the respective dimension ("
544	             << tileType.getDimSize(i) << ")";
545	  }
546	  return success();
547	}
