549	LogicalResult BoundedAttr::verifyWithAssumeOp(Operation *op) const {
550	  auto tileType =
551	      llvm::dyn_cast<cuda_tile::TileType>(llvm::cast<AssumeOp>(op).getType());
552	  if (!tileType)
553	    return op->emitOpError()
554	           << "'" << name << "' is valid only for tile of integer values";
555	  auto intType = llvm::dyn_cast<IntegerType>(tileType.getElementType());
556	  if (!intType)
557	    return op->emitOpError()
558	           << "'" << name << "' is valid only for tile of integer values";
559	  int64_t minVal = getMinSignedValueForBitwidth(intType.getWidth());
560	  int64_t maxVal = getMaxSignedValueForBitwidth(intType.getWidth());
561	  if (getLb().has_value() && (*getLb() > maxVal || *getLb() < minVal))
562	    return op->emitOpError()
563	           << "'" << name << "' expects lower bound to be within [" << minVal
564	           << ", " << maxVal << "]";
565	  if (getUb().has_value() && (*getUb() > maxVal || *getUb() < minVal))
566	    return op->emitOpError()
567	           << "'" << name << "' expects upper bound to be within [" << minVal
568	           << ", " << maxVal << "]";
569	  if (getLb().has_value() && getUb().has_value() && *getLb() > *getUb())
570	    return op->emitOpError()
571	           << "'" << name
572	           << "' expects lower bound to be less than or equal to upper bound";
573	  return success();
574	}
